        return tuple(self.visit(elt) for elt in node.elts)

    def visit_Dict(self, node):
        result = {}
        for key_node, value_node in zip(node.keys, node.values):
            key = self.visit(key_node)
            value = self.visit(value_node)
            result[key] = value
        return result

    def visit_Subscript(self, node):
        if isinstance(node.value, ast.Name):
            var_name = node.value.id
            if var_name in self.variables:
                container = self.variables[var_name]
            else:
                raise NameError(f"Name '{var_name}' not defined")
        else:
            container = self.visit(node.value)

        index = self.visit(node.slice)
        return container[index]

    def visit_Index(self, node):
        return self.visit(node.value)

def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Safely evaluates a Python expression string using input_data as a variable.

    Args:
        transform_map_expr: A Python expression string to evaluate
        input_data: A dictionary containing input data

    Returns:
        The result of evaluating the expression
    """
    try:
        # Parse the expression into an AST
        tree = ast.parse(transform_map_expr, mode='eval')

        # Create evaluator with input_data available as 'input_data'
        evaluator = SafeExpressionEvaluator({'input_data': input_data})

        # Evaluate the AST
        result = evaluator.visit(tree.body)

        return result
    except Exception as e:
        raise ValueError(f"Error evaluating expression: {str(e)}")
